// ============================================================
// FONTES RSS вЂ” FederaГ§Гµes GaГєchas confirmadas
// ativo: true = serГЎ buscado a cada 6h
// ativo: false = aguardando validaГ§ГЈo
// ============================================================
const fontes = [

  // вњ… RSS CONFIRMADOS вЂ” WordPress com /feed nativo
  {
    nome: 'FederaГ§ГЈo GaГєcha de Ciclismo',
    url_rss: 'https://www.fgc.com.br/feed/',
    esporte_slug: 'ciclismo',
    ativo: true
  },
  {
    nome: 'IFBB RS (Fisiculturismo)',
    url_rss: 'https://www.ifbbrs.com.br/feed/',
    esporte_slug: 'fisiculturismo',
    ativo: true
  },
  {
    nome: 'FederaГ§ГЈo GaГєcha de JudГґ',
    url_rss: 'https://judors.com.br/feed/',
    esporte_slug: 'judo',
    ativo: true
  },

  // вњ… RSS de referГЄncia nacional
  {
    nome: 'GloboEsporte',
    url_rss: 'https://ge.globo.com/rss/atomfeed.xml',
    esporte_slug: 'futebol',
    ativo: true
  },

  // вЏі SEM RSS вЂ” SPA/custom (scraping futuro via Apify)
  // FGARS (Atletismo): https://www.fgars.org/#/pages/news вЂ” SPA, sem RSS
  // TГЄnis Integrado: https://www.tenisintegrado.com.br вЂ” backend Java, sem RSS

  // вњ… RSS CONFIRMADOS вЂ” validados em 2026-03-16
  {
    nome: 'FederaГ§ГЈo GaГєcha de Basketball',
    url_rss: 'https://basquetegaucho.com.br/feed/',
    esporte_slug: 'basquete',
    ativo: true
  },

  // вЏі SEM RSS вЂ” aguardando validaГ§ГЈo ou site sem feed
  {
    nome: 'FederaГ§ГЈo GaГєcha de Futebol',
    url_rss: 'https://www.fgf.com.br/feed',
    esporte_slug: 'futebol',
    ativo: false
  },
  {
    nome: 'FederaГ§ГЈo GaГєcha de VГґlei',
    url_rss: 'https://www.fgv.com.br/feed',
    esporte_slug: 'volei',
    ativo: false
  }
];

return fontes
  .filter(f => f.ativo)
  .map(f => ({ json: f }));

// Parsear XML do RSS e Atom вЂ” suporta ambos os formatos
const xml = $input.item.json.data;
const fonte_nome = $('рџ“‹ Lista de Fontes RSS').item.json.nome;
const esporte_slug = $('рџ“‹ Lista de Fontes RSS').item.json.esporte_slug;

if (!xml || typeof xml !== 'string') {
  console.log(`вљ пёЏ Sem resposta de ${fonte_nome}`);
  return [];
}

// Detecta formato: Atom usa <entry>, RSS usa <item>
const isAtom = /<feed[^>]*xmlns[^>]*>/i.test(xml) || /<entry[^>]*>/i.test(xml);
console.log(`${fonte_nome}: formato ${isAtom ? 'Atom' : 'RSS'}`);

// Decodifica entidades HTML (named + numeric)
const decodeEntities = (str) => {
  if (!str) return str;
  const entities = {
    '&amp;': '&', '&lt;': '<', '&gt;': '>',
    '&nbsp;': ' ', '&aacute;': 'ГЎ', '&eacute;': 'Г©', '&iacute;': 'Г­',
    '&oacute;': 'Гі', '&uacute;': 'Гє', '&Aacute;': 'ГЃ', '&Eacute;': 'Г‰',
    '&Iacute;': 'ГЌ', '&Oacute;': 'Г“', '&Uacute;': 'Гљ', '&atilde;': 'ГЈ',
    '&otilde;': 'Гµ', '&Atilde;': 'Гѓ', '&Otilde;': 'Г•', '&ccedil;': 'Г§',
    '&Ccedil;': 'Г‡', '&agrave;': 'Г ', '&egrave;': 'ГЁ', '&acirc;': 'Гў',
    '&ecirc;': 'ГЄ', '&ocirc;': 'Гґ', '&ucirc;': 'Г»', '&ndash;': 'вЂ“',
    '&mdash;': 'вЂ”', '&hellip;': 'вЂ¦', '&lsquo;': '\u2018', '&rsquo;': '\u2019',
    '&ldquo;': '\u201C', '&rdquo;': '\u201D'
  };
  return str
    .replace(/&#x([0-9a-fA-F]+);/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#([0-9]+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)))
    .replace(/&[a-zA-Z]+;/g, (ent) => entities[ent] || ent);
};

const extract = (text, tag) => {
  const r = new RegExp(
    `<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>|<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`,
    'i'
  );
  const m = text.match(r);
  return (m ? (m[1] || m[2]) : '').trim();
};

const items = [];

if (isAtom) {
  // в”Ђв”Ђ ATOM в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const entryRegex = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
  let match;
  while ((match = entryRegex.exec(xml)) !== null) {
    const entry = match[1];
    const titulo = decodeEntities(extract(entry, 'title'));

    // Atom: <link href="URL" rel="alternate" /> ou <link href="URL" />
    const linkMatch = entry.match(/<link[^>]+href=["']([^"']+)["'][^>]*(?:rel=["']alternate["'][^>]*)?\/?>/) ||
                      entry.match(/<link[^>]+rel=["']alternate["'][^>]+href=["']([^"']+)["'][^>]*\/?>/);
    const fonte_url = linkMatch ? linkMatch[1] : null;

    // Atom: <summary> ou <content>
    const descricao = extract(entry, 'summary') || extract(entry, 'content') || '';
    const resumo = decodeEntities(descricao.replace(/<[^>]+>/g, '').trim().substring(0, 300)) || null;

    // Imagem: media:thumbnail ou enclosure
    const thumbMatch = entry.match(/<media:thumbnail[^>]+url=["']([^"']+)["']/i) ||
                       entry.match(/<enclosure[^>]+url=["']([^"']+)["'][^>]+type=["']image/i);
    const imagem_url = thumbMatch ? thumbMatch[1] : null;

    if (titulo && fonte_url) {
      items.push({ titulo, fonte_url, fonte_nome, resumo, imagem_url, esporte_slug });
    }
  }
} else {
  // в”Ђв”Ђ RSS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const item = match[1];
    const titulo = decodeEntities(extract(item, 'title'));
    const link = extract(item, 'link') || extract(item, 'guid');
    const descricao = extract(item, 'description');

    const linkAtomMatch = item.match(/<link[^>]+href=["']([^"']+)["'][^>]*\/?>/i);
    const fonte_url = link || (linkAtomMatch ? linkAtomMatch[1] : null);

    const imgMatch = descricao.match(/<img[^>]+src=["']([^"']+)["']/i);
    const imagem_url = imgMatch ? imgMatch[1] : null;
    const resumo = decodeEntities(descricao.replace(/<[^>]+>/g, '').trim().substring(0, 300)) || null;

    if (titulo && fonte_url) {
      items.push({ titulo, fonte_url, fonte_nome, resumo, imagem_url, esporte_slug });
    }
  }
}

console.log(`${fonte_nome}: ${items.length} itens encontrados`);
return items.map(i => ({ json: i, pairedItem: { item: 0 } }));

// Processa TODOS os itens вЂ” HTML de $input.all(), metadados de Parsear XML pelo Г­ndice
function extractFromAnchor(htmlStr, anchorRegex) {
  const m = htmlStr.match(anchorRegex);
  if (!m) return null;
  const start = htmlStr.indexOf(m[0]);
  if (start === -1) return null;
  const chunk = htmlStr.substring(start, start + 25000);
  const paragraphs = (chunk.match(/<p[^>]*>[\s\S]*?<\/p>/gi) || [])
    .map(p => p.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
    .filter(p => p.length > 40);
  if (paragraphs.length === 0) return null;
  return '<p>' + paragraphs.slice(0, 40).join('</p>\n<p>') + '</p>';
}

const anchors = [
  /<article[^>]*>/i,
  /<div[^>]+class=["'][^"']*entry-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*post-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*td-post-content[^"']*["']/i,
  /<div[^>]+class=["'][^"']*article-body[^"']*["']/i,
  /<div[^>]+class=["'][^"']*materia-conteudo[^"']*["']/i,
  /<div[^>]+class=["'][^"']*conteudo[^"']*["']/i,
  /<div[^>]+class=["'][^"']*content[^"']*["']/i,
  /<main[^>]*>/i,
];

const httpItems = $input.all();
const parsedItems = $('рџ”Ќ Parsear XML do RSS').all();
const results = [];

for (let i = 0; i < httpItems.length; i++) {
  const html = httpItems[i].json.data || '';
  const meta = parsedItems[i] ? parsedItems[i].json : {};

  const titulo = meta.titulo || '';
  const fonte_url = meta.fonte_url || '';
  const fonte_nome = meta.fonte_nome || '';
  const resumo = meta.resumo || null;
  const esporte_slug = meta.esporte_slug || '';

  // Extrai og:image
  let imagem_url = meta.imagem_url || null;
  const ogImagePatterns = [
    /<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i,
    /<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i,
    /<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i,
    /<meta[^>]+content=["']([^"']+)["'][^>]+name=["']twitter:image["']/i,
  ];
  for (const pattern of ogImagePatterns) {
    const m = html.match(pattern);
    if (m && m[1] && m[1].startsWith('http')) {
      imagem_url = m[1];
      break;
    }
  }

  // Extrai conteГєdo
  let conteudo = null;
  for (const anchor of anchors) {
    const extracted = extractFromAnchor(html, anchor);
    if (extracted && extracted.length > 200) {
      conteudo = extracted;
      break;
    }
  }
  if (!conteudo) {
    const allP = (html.match(/<p[^>]*>[\s\S]*?<\/p>/gi) || [])
      .map(p => p.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
      .filter(p => p.length > 60);
    if (allP.length >= 2) {
      conteudo = '<p>' + allP.slice(0, 30).join('</p>\n<p>') + '</p>';
    }
  }

  console.log(`рџ“° [${i+1}/${httpItems.length}] ${titulo} вЂ” conteudo: ${conteudo ? conteudo.length + ' chars' : 'nГЈo extraГ­do'} | imagem: ${imagem_url ? 'ok' : 'null'}`);
  results.push({ json: { titulo, fonte_url, fonte_nome, resumo, esporte_slug, conteudo: conteudo || null, imagem_url } });
}

return results;

const response = $input.item.json;
const titulo = $('рџ“ќ Extrair conteГєdo').item.json.titulo || '(sem tГ­tulo)';

if (response.success) {
  console.log(`вњ… Salva: ${titulo}`);
} else if (response.skipped) {
  console.log(`вЏ­пёЏ Duplicata: ${titulo}`);
} else {
  console.log(`вќЊ Erro: ${titulo} вЂ” ${JSON.stringify(response)}`);
}

return $input.all();
